import{_ as t,o as l,c as i,ag as e}from"./chunks/framework.CQYuu_FX.js";const u=JSON.parse('{"title":"テイクアウト管理","description":"","frontmatter":{"title":"テイクアウト管理"},"headers":[],"relativePath":"tenant/09-takeout.md","filePath":"tenant/09-takeout.md"}'),r={name:"tenant/09-takeout.md"};function n(o,a,s,d,h,p){return l(),i("div",null,[...a[0]||(a[0]=[e(`<h1 id="_9-テイクアウト管理" tabindex="-1">9. テイクアウト管理 <a class="header-anchor" href="#_9-テイクアウト管理" aria-label="Permalink to &quot;9. テイクアウト管理&quot;">​</a></h1><p>テイクアウト管理では、持ち帰り注文の受付、受取時間、オンライン決済、注文ステータスを管理します。</p><h2 id="利用開始前の設定" tabindex="-1">利用開始前の設定 <a class="header-anchor" href="#利用開始前の設定" aria-label="Permalink to &quot;利用開始前の設定&quot;">​</a></h2><ol><li>店舗設定でテイクアウトを有効にします。</li><li>受付時間、受取可能時間、注文上限を設定します。</li><li>テイクアウト対象商品を確認します。</li><li>決済方法を確認します。</li><li>お客様用の案内URLまたはQRコードを掲示します。</li></ol><h2 id="注文受付の流れ" tabindex="-1">注文受付の流れ <a class="header-anchor" href="#注文受付の流れ" aria-label="Permalink to &quot;注文受付の流れ&quot;">​</a></h2><ol><li>お客様がテイクアウトページを開きます。</li><li>商品、数量、受取時間、連絡先を入力します。</li><li>必要に応じて決済を行います。</li><li>店舗側の管理画面に注文が表示されます。</li><li>調理、受け渡し、完了のステータスを更新します。</li></ol><h2 id="営業中の確認ポイント" tabindex="-1">営業中の確認ポイント <a class="header-anchor" href="#営業中の確認ポイント" aria-label="Permalink to &quot;営業中の確認ポイント&quot;">​</a></h2><ul><li>受取時間に無理がないか確認してください。</li><li>品切れ商品がテイクアウト画面に残っていないか確認してください。</li><li>受け渡し済みの注文は完了にしてください。</li><li>連絡先が必要な場合は、店舗の個人情報管理ルールに従って扱ってください。</li></ul><h2 id="誤会計の取消-pos-レジで会計した場合" tabindex="-1">誤会計の取消（POS レジで会計した場合） <a class="header-anchor" href="#誤会計の取消-pos-レジで会計した場合" aria-label="Permalink to &quot;誤会計の取消（POS レジで会計した場合）&quot;">​</a></h2><p>POS レジで <strong>ゲートウェイを経由しないで会計したテイクアウト</strong>（現金 / 手動 card / 手動 qr）を、後から管理者が論理取消できます。取引ジャーナルに「会計取消」ボタンが表示されます。</p><p><strong>取消可能条件</strong>:</p><ul><li>POS レジで会計済みになっている</li><li>支払方法が現金 / 手動 card / 手動 qr（ゲートウェイ非経由）</li><li>分割会計ではない</li><li>まだ返金・取消していない</li></ul><p><strong>取消できないもの（本機能では）</strong>:</p><ul><li>オンライン決済済みのテイクアウト → 本機能ではなく<strong>返金</strong>で処理します（下記「オンライン決済テイクアウトの返金」を参照）</li><li>分割会計 / 返金済み / 既に取消済み</li></ul><p>操作場所と動作は POS レジ章「通常会計も取り消せます」を参照してください。現金会計の取消ではレジ残高も調整されますが、お客様への現金返却は別途行ってください。</p><h2 id="オンライン決済テイクアウトの返金" tabindex="-1">オンライン決済テイクアウトの返金 <a class="header-anchor" href="#オンライン決済テイクアウトの返金" aria-label="Permalink to &quot;オンライン決済テイクアウトの返金&quot;">​</a></h2><p>オンライン決済済みのテイクアウト注文で誤会計があった場合は、<strong>返金</strong>で処理します。「会計取消」ではなく「返金」機能を使います。</p><h3 id="実証済みの範囲" tabindex="-1">実証済みの範囲 <a class="header-anchor" href="#実証済みの範囲" aria-label="Permalink to &quot;実証済みの範囲&quot;">​</a></h3><ul><li><strong>Stripe Connect Checkout で決済したテイクアウト</strong> で、お客様がクレジットカード決済したケース</li><li>返金が必要な場合は、POSLAサポートへご相談ください</li><li>返金すると、お客様のカード明細へ返金内容が反映されます</li></ul><h3 id="まだ一般化していない範囲-別対応-要確認" tabindex="-1">まだ一般化していない範囲（別対応 / 要確認） <a class="header-anchor" href="#まだ一般化していない範囲-別対応-要確認" aria-label="Permalink to &quot;まだ一般化していない範囲（別対応 / 要確認）&quot;">​</a></h3><ul><li>店頭 POS レジの Stripe Terminal で決済したテイクアウト（実データ 0 件のため運用検証未実施）</li><li>一部返金など、個別確認が必要なケース</li><li>オンライン決済テイクアウトの取消を返金以外の方法で処理したいケース</li></ul><p>これらが必要になった場合は、POSLAサポートへご相談ください。</p><h3 id="実行後のお客様への影響" tabindex="-1">実行後のお客様への影響 <a class="header-anchor" href="#実行後のお客様への影響" aria-label="Permalink to &quot;実行後のお客様への影響&quot;">​</a></h3><ul><li>Stripe 側で返金処理が実行されると、お客様のカード明細に返金が反映されます（通常 5〜10 営業日）</li><li>テナント側の売上レポートには「返金済」として表示され、実売上からは自動除外されます</li><li>注文自体の状態（調理・受取のステータス）は、返金しても自動では変わりません。必要に応じてテイクアウト管理画面で個別対応してください</li></ul><h2 id="お客様画面でのエラー表示" tabindex="-1">お客様画面でのエラー表示 <a class="header-anchor" href="#お客様画面でのエラー表示" aria-label="Permalink to &quot;お客様画面でのエラー表示&quot;">​</a></h2><p>Stripe 決済が完了したのに、POSLA 側で注文の記録に失敗したごく稀なケースでは、お客様の画面に次のメッセージが表示されます。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>決済確認に失敗しました</span></span>
<span class="line"><span>決済は Stripe 側で完了している可能性があります。</span></span>
<span class="line"><span>お手数ですが、下記の注文番号を添えて店舗まで直接お問い合わせください。</span></span>
<span class="line"><span>注文番号: XXXXXXXX</span></span></code></pre></div><p>この場合、店舗（運営）側では次の手順で確認してください。</p><ol><li>POSLAサポートへ連絡して、注文番号と発生時刻を伝える</li><li>店舗側でも、同じ時間帯の注文一覧と決済状況を確認する</li><li>必要に応じて、POSLAサポートの案内に従って返金または注文対応を行う</li></ol><p>※ キャンセル表示（オレンジ「決済がキャンセルされました」）とは別の表示です。お客様がキャンセル操作をした場合はキャンセル画面、決済完了しているのに記録失敗した場合は上記のエラー画面になります。</p><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>注文が入らない</td><td>テイクアウトが有効か、受付時間内か確認してください。</td></tr><tr><td>受取時間が選べない</td><td>受付時間、準備時間、注文上限を確認してください。</td></tr><tr><td>決済が完了しない</td><td>決済設定とお客様の入力状況を確認してください。</td></tr><tr><td>お客様画面に「決済確認に失敗しました」と表示される</td><td>上記「お客様画面でのエラー表示」を参照し、POSLAサポートへご相談ください。</td></tr><tr><td>注文を停止したい</td><td>テイクアウト設定を無効にし、案内QRの掲示も確認してください。</td></tr></tbody></table>`,32)])])}const b=t(r,[["render",n]]);export{u as __pageData,b as default};
